const handleSubmit = async (e) => {
  e.preventDefault();

  const method = selectedClient ? 'PUT' : 'POST';
  const url = selectedClient
    ? `http://localhost:3001/clients/${selectedClient.codeCli}`
    : 'http://localhost:3001/clients';

  try {
    const res = await fetch(url, {
      method,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(formData),
    });

    if (!res.ok) {
      const errorText = await res.text();
      throw new Error(errorText || 'Erreur lors de la soumission');
    }

    resetForm();
    if (onSuccess) onSuccess();
  } catch (err) {
    alert(err.message);
  }
};

const handleDelete = async () => {
  if (!selectedClient) return;

  if (!window.confirm('Supprimer ce client ?')) return;

  try {
    const res = await fetch(`http://localhost:3001/clients/${selectedClient.codeCli}`, {
      method: 'DELETE',
    });

    if (!res.ok) {
      const errorText = await res.text();
      throw new Error(errorText || 'Erreur lors de la suppression');
    }

    resetForm();
    if (onSuccess) onSuccess();
  } catch (err) {
    alert(err.message);
  }
};
